import React, { FC, useMemo, useEffect, useCallback, useRef } from 'react';
import { connect } from 'react-redux';
import { Dispatch, bindActionCreators } from 'redux';
import { useFocusEffect } from '@react-navigation/native';

import { PointsActions } from '../../redux/ducks/points';
import { AppReducers } from '../../redux/reducers/Models';
import PointsExtractView from './view';
import { eventScreenViewV3 } from '~/constants/functions';

const PointsExtractBase: FC<any> = ({
  route,
  fintechPointsReducer,
  navigation,
  requestPointsBalance,
  requestPointsExtract,
  setTransactionsFilters,
  clearTransactionsFilters,
  setExpiringFilters,
  clearExpiringFilters,
}) => {
  const hasTrackedScreenView = useRef(false);

  useFocusEffect(
    useCallback(() => {
      if (!hasTrackedScreenView.current) {
        eventScreenViewV3('extrato_hub_recompensas', 'hub_recompensas_spmais', 'monetizacao', {
          location_1: 'monetizacao',
          location_2: 'hub_recompensas_spmais',
          location_3: 'extrato_hub_recompensas',
        });
        hasTrackedScreenView.current = true;
      }

      return () => {
        hasTrackedScreenView.current = false;
      };
    }, [])
  );

  useEffect(() => {
    if (
      fintechPointsReducer?.points === undefined ||
      fintechPointsReducer?.isErrorBalance
    ) {
      requestPointsBalance();
    }

    requestPointsExtract();
  }, []);

  const pointsAvailable = useMemo(() => {
    return fintechPointsReducer?.points || 0;
  }, [fintechPointsReducer]);

  const handleGoBack = useCallback(() => {
    navigation.goBack();
  }, [navigation]);

  const view = useMemo(() => {
    return (
      <PointsExtractView
        pointsAvailable={pointsAvailable}
        handleGoBack={handleGoBack}
        extractData={fintechPointsReducer?.extractData}
        isLoadingExtract={fintechPointsReducer?.isLoadingExtract || false}
        isLoadingBalance={fintechPointsReducer?.isLoadingBalance || false}
        hasError={fintechPointsReducer?.isErrorExtract}
        requestPointsExtract={requestPointsExtract}
        appliedTransactionsFilters={fintechPointsReducer?.appliedTransactionsFilters}
        appliedExpiringFilters={fintechPointsReducer?.appliedExpiringFilters}
        setTransactionsFilters={setTransactionsFilters}
        clearTransactionsFilters={clearTransactionsFilters}
        setExpiringFilters={setExpiringFilters}
        clearExpiringFilters={clearExpiringFilters}
        navigation={navigation}
      />
    );
  }, [
    fintechPointsReducer,
    pointsAvailable,
    handleGoBack,
    requestPointsExtract,
    setTransactionsFilters,
    clearTransactionsFilters,
    setExpiringFilters,
    clearExpiringFilters,
    navigation,
  ]);

  return view;
};

export const mapStateToProps = ({ pointsReducer }: AppReducers) => {
  return {
    fintechPointsReducer: pointsReducer,
  };
};

export const mapDispatchToProps = (dispatch: Dispatch) => {
  return bindActionCreators(
    {
      ...PointsActions,
    },
    dispatch,
  );
};

export default connect(mapStateToProps, mapDispatchToProps)(PointsExtractBase);

