  SearchUsed,
  SeparatorHorizontal,
  Text,
  Box,
  Icon,
  ListCardTransition,
} from '@semparar/design-system-app';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import { propsItemsListCardTransition } from '@semparar/design-system-app/src/atomic/organisms/ListCardTransition/Models';
import React, {
  FC,
  useState,
  useMemo,
  useRef,
  useCallback,
  useEffect,
} from 'react';
import { Platform, RefreshControl, InteractionManager } from 'react-native';
import { NavigationProp, useNavigation } from '@react-navigation/native';
import theme from '../../styles/theme';
import ApiError from '../../atomic/organisms/ApiError';
import PointsInfoBottomSheet from '../../atomic/organisms/PointsInfoBottomSheet';
import FiltersBottomSheet from '../../atomic/organisms/FiltersBottomSheet';
import BasicScreen from '../../atomic/templates/BasicScreen';
import useDebounce from '../../hooks/useDebounce';
import { eventSelectContent, eventModalView } from '~/constants/functions';
import { processPointsExtractData } from '../../redux/sagas/points/processExtractData';
import { filterTransactionsByText, getPlaceholder, applyTransactionsFilters, applyExpiringFilters, filterExpiringByText } from './utils';
import { PointsExtractProps } from './Models';
import { PropsRootStack } from '../../routes/Models';

const STRINGS = {
  EMPTY_ALL_LIST: 'Para ganhar pontos, use seu cartão Sem Parar Mais ou a Tag.',
  EMPTY_EXPIRING_LIST: 'Você não tem pontos a expirar.',
  EMPTY_SEARCH_RESULTS: 'Não encontramos resultados para sua busca.',
} as const;

interface EmptyListProps {
  label: string;
}

const EmptyList = React.memo<EmptyListProps>(({ label }) => (
  <Box width="100%" justify="center" align="center">
    <Icon
      name="icon-invoice-error"
      size="lg"
      color="INTENSE_COLOR_02"
      mt="meddium"
    />
    <Text
      type="paragraphLG"
      pd="innerGreat"
      color="INTENSE_COLOR_03"
      align="center"
    >
      {label}
    </Text>
  </Box>
));

interface TransactionsListProps {
  items: propsItemsListCardTransition[];
  isLoading: boolean;
}

const TransactionsList = React.memo<TransactionsListProps>(({ items, isLoading }) => (
  <ListCardTransition
    items={items}
    isLoading={isLoading}
    scrollEnabled={false}
    mb="meddium"
  />
));

interface ExpiringListProps {
  items: propsItemsListCardTransition[];
  isLoading: boolean;
}

const ExpiringList = React.memo<ExpiringListProps>(({ items, isLoading }) => (
  <ListCardTransition
    items={items}
    isLoading={isLoading}
    scrollEnabled={Platform.OS !== 'ios'}
    mb="meddium"
  />
));

const PointsExtract: FC<PointsExtractProps> = ({
  hasError,
  handleGoBack,
  pointsAvailable,
  extractData,
  isLoadingExtract,
  isLoadingBalance,
  requestPointsExtract,
  appliedTransactionsFilters,
  appliedExpiringFilters,
  setTransactionsFilters,
  clearTransactionsFilters,
  setExpiringFilters,
  clearExpiringFilters,
  navigation: navigationProp,
}) => {
  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
  const [activeTab, setActiveTab] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [visitedTabs, setVisitedTabs] = useState([0]);
  const [transactionsData, setTransactionsData] = useState<propsItemsListCardTransition[]>([]);
  const [expiringData, setExpiringData] = useState<propsItemsListCardTransition[]>([]);

  const [searchText, setSearchText, debouncedSearchText] = useDebounce('', 400);
  const hasTrackedSearchPress = useRef(false);

  useEffect(() => {
    if (!isLoadingExtract && isRefreshing) {
      setIsRefreshing(false);
    }
  }, [isLoadingExtract, isRefreshing]);

  useEffect(() => {
    if (searchText.length === 0) {
      hasTrackedSearchPress.current = false;
    }
  }, [searchText]);



  const modalizeRefInfo = useRef<PropsModalizeRef>(null );
  const modalizeRefFilters = useRef<PropsModalizeRef>(null);

  const activeFiltersCount = useMemo(() => {
    let count = 0;

    if (activeTab === 0) {
      if (appliedTransactionsFilters?.period) count++;
      if (appliedTransactionsFilters?.types?.length) count++;
    } else {
      if (appliedExpiringFilters?.period) count++;
    }

    return count > 0 ? count.toString() : undefined;
  }, [activeTab, appliedTransactionsFilters, appliedExpiringFilters]);

  const filteredTransactions = useMemo(() => {
    if (!extractData?.transactions) {
      return [];
    }

    let transactions = extractData.transactions;

    if (debouncedSearchText && debouncedSearchText.trim() !== '' && activeTab === 0) {
      transactions = filterTransactionsByText(
        transactions,
        debouncedSearchText,
        false,
      );
    }

    return applyTransactionsFilters(transactions, appliedTransactionsFilters);
  }, [extractData?.transactions, debouncedSearchText, appliedTransactionsFilters, activeTab]);

  const filteredExpiringPoints = useMemo(() => {
    if (!extractData?.expiringPoints) {
      return [];
    }

    let expiringPoints = extractData.expiringPoints;

    if (debouncedSearchText && debouncedSearchText.trim() !== '' && activeTab === 1) {
      expiringPoints = filterExpiringByText(
        expiringPoints,
        debouncedSearchText,
      );
    }

    return applyExpiringFilters(expiringPoints, appliedExpiringFilters);
  }, [extractData?.expiringPoints, debouncedSearchText, appliedExpiringFilters, activeTab]);

  useEffect(() => {
    if (!extractData) return;

    let cancelled = false;
    const task = InteractionManager.runAfterInteractions(() => {
      if (cancelled) return;
      const processed = processPointsExtractData({
        ...extractData,
        transactions: filteredTransactions,
        expiringPoints: [],
      }, navigation);
      if (!cancelled) {
        setTransactionsData(processed.mappedTransactions);
      }
    });

    return () => {
      cancelled = true;
      task.cancel();
    };
  }, [extractData, filteredTransactions, navigation]);

  useEffect(() => {
    if (!extractData) return;

    let cancelled = false;
    const task = InteractionManager.runAfterInteractions(() => {
      if (cancelled) return;
      const processed = processPointsExtractData({
        ...extractData,
        transactions: [],
        expiringPoints: filteredExpiringPoints,
      }, navigation);
      if (!cancelled) {
        setExpiringData(processed.mappedExpiring);
      }
    });

    return () => {
      cancelled = true;
      task.cancel();
    };
  }, [extractData, filteredExpiringPoints, navigation]);

  const transactionsEmptyMessage = useMemo(() => {
    const hasSearchText = debouncedSearchText && debouncedSearchText.trim() !== '';
    const hasActiveFilters = !!(appliedTransactionsFilters?.period || appliedTransactionsFilters?.types?.length);
    return (hasSearchText || hasActiveFilters)
      ? STRINGS.EMPTY_SEARCH_RESULTS
      : STRINGS.EMPTY_ALL_LIST;
  }, [debouncedSearchText, appliedTransactionsFilters]);

  const expiringEmptyMessage = useMemo(() => {
    const hasSearchText = debouncedSearchText && debouncedSearchText.trim() !== '';
    const hasActiveFilters = !!appliedExpiringFilters?.period;
    return (hasSearchText || hasActiveFilters)
      ? STRINGS.EMPTY_SEARCH_RESULTS
      : STRINGS.EMPTY_EXPIRING_LIST;
  }, [debouncedSearchText, appliedExpiringFilters]);

  const shouldShowTransactionsList = isLoadingExtract || transactionsData.length > 0;
  const shouldShowExpiringList = isLoadingExtract || expiringData.length > 0;

  const transactionsTabContent = useMemo(() => {
    if (activeTab !== 0) return null;

    return (
      <>
        {shouldShowTransactionsList ? (
          <TransactionsList items={transactionsData} isLoading={isLoadingExtract} />
        ) : (
          <EmptyList label={transactionsEmptyMessage} />
        )}
      </>
    );
  }, [activeTab, transactionsData, shouldShowTransactionsList, transactionsEmptyMessage, isLoadingExtract]);

  const expiringTabContent = useMemo(() => {
    if (!visitedTabs.includes(1) || activeTab !== 1) return null;

    return (
      <>
        {shouldShowExpiringList ? (
          <ExpiringList items={expiringData} isLoading={isLoadingExtract} />
        ) : (
          <EmptyList label={expiringEmptyMessage} />
        )}
      </>
    );
  }, [visitedTabs, activeTab, expiringData, shouldShowExpiringList, expiringEmptyMessage, isLoadingExtract]);

  const extractTabs = useMemo(() => [
    {
      id: 0,
      title: 'Todos',
      component: transactionsTabContent,
    },
    {
      id: 1,
      title: 'A expirar',
      component: expiringTabContent,
    },
  ], [transactionsTabContent, expiringTabContent]);

  const handleSearchChange = useCallback((text: string) => {
    setSearchText(text);
  }, [setSearchText]);


  const handleTabChange = useCallback((index: number) => {
    setActiveTab(index);
    setVisitedTabs((prev) => (prev.includes(index) ? prev : [...prev, index]));
    setSearchText('');
    hasTrackedSearchPress.current = false;
  }, [setSearchText]);

  const handleRefresh = useCallback(() => {
    setIsRefreshing(true);
    requestPointsExtract();
  }, [requestPointsExtract]);

  const handleError = useCallback(() => {
    requestPointsExtract();
  }, [requestPointsExtract]);

  const handleIconInfoPress = useCallback(() => {
    modalizeRefInfo.current?.open?.();
  }, []);

  const handleFilterIconPress = useCallback(() => {
    modalizeRefFilters.current?.open?.();
  }, []);

  const handleApplyFilters = useCallback((filters: Record<number, any>) => {
    if (activeTab === 0) {
      const period = filters[0];
      const types = filters[1];

      if (!period && !types) {
        clearTransactionsFilters();
      } else {
        setTransactionsFilters({ period, types: types ? [types] : undefined });
      }
    } else {
      const period = filters[0];

      if (!period) {
        clearExpiringFilters();
      } else {
        setExpiringFilters({ period });
      }
    }
  }, [activeTab, setTransactionsFilters, clearTransactionsFilters, setExpiringFilters, clearExpiringFilters]);

  const filterGroups = useMemo(() => {
    if (activeTab === 0 && extractData?.transactionsFilters) {
      return [
        {
          label: 'Períodos',
          options: extractData.transactionsFilters.periods,
        },
        {
          label: 'Tipos de lançamentos',
          options: extractData.transactionsFilters.types,
        },
      ];
    } else if (activeTab === 1 && extractData?.expiringFilters) {
      return [
        {
          label: 'Períodos',
          options: extractData.expiringFilters.periods,
        },
      ];
    }
    return [];
  }, [activeTab, extractData]);

  const initialFilters = useMemo(() => {
    if (activeTab === 0) {
      return {
        0: appliedTransactionsFilters?.period,
        1: appliedTransactionsFilters?.types?.[0],
      };
    } else {
      return {
        0: appliedExpiringFilters?.period,
      };
    }
  }, [activeTab, appliedTransactionsFilters, appliedExpiringFilters]);

  if (hasError) {
    return (
      <ApiError
        title="Algo deu errado!"
        subTitle="Por favor, tente de novo."
        isLoading={isLoadingExtract}
        onPress={handleError}
      />
    );
  }

  return (
    <>
      <BasicScreen
        errorButtonOnPress={handleError}
        leftIconOnPress={handleGoBack}
        title="Extrato"
        hasScroll
        scrollViewProps={{
          refreshControl: (
            <RefreshControl
              onRefresh={handleRefresh}
              refreshing={isRefreshing}
              tintColor={theme.colors.BRAND_BASE_01}
            />
          ),
        }}
      >
        <Box ml="smaller" mr="smaller" mt="smaller" mb="xxxs">
          <CardPoints
              icon="icon-benefits"
              iconInfo="icon-help"
              title="Pontos disponíveis"
              valuePoints={pointsAvailable ? pointsAvailable.toLocaleString('pt-br') : '0'}
              hideBottom
              isLoading={isLoadingBalance}
              onPressIconInfo={() => {
                eventSelectContent({
                  content_type: 'cta',
                  content_id: 'informacao_pontos',
                  location_1: 'monetizacao',
                  location_2: 'hub_recompensas_spmais',
                  location_3: 'extrato_hub_recompensas',
                });
                handleIconInfoPress();
              }}
            />

            <Text
              type="paragraphXXXL"
              mb="xxxxs"
              mt="xxs"
              color="INTENSE_COLOR_05"
            >
              Lançamentos
            </Text>

            <SeparatorHorizontal
              borderWidth="smaller"
              borderColor="BRAND_COMPLEMENT_02"
              height={1}
              mb="xxxxs"
              width="100%"
            />
            <SearchUsed
              placeholder={getPlaceholder(activeTab === 1)}
              onChangeText={handleSearchChange}
              value={searchText}
              showIcon={!!activeFiltersCount}
              firstIcon={undefined}
              onPressIn={() => {
                if (!hasTrackedSearchPress.current) {
                  eventSelectContent({
                    content_type: 'form',
                    content_id: 'pesquisar',
                    location_1: 'monetizacao',
                    location_2: 'hub_recompensas_spmais',
                    location_3: 'extrato_hub_recompensas',
                  });
                  hasTrackedSearchPress.current = true;
                }
              }}
              numberIcon={activeFiltersCount}
              secondIcon="icon-filter-settings"
              secondOnPress={() => {
                eventModalView({
                  content_id: 'filtro_extrato_hub',
                  location_1: 'monetizacao',
                  location_2: 'hub_recompensas_spmais',
                  location_3: 'extrato_hub_recompensas'
                });
                handleFilterIconPress();
              }}
              showFilter
            />
        </Box>

        <Box
          ml={isLoadingExtract ? 'xs' : 'none'}
          mr={isLoadingExtract ? 'xs' : 'none'}
        >
          <Tabs
              items={extractTabs}
              showBackground={false}
              hasScroll={false}
              loadingType="light"
              onChange={(index) => {
                if(index === 0) {
                  eventSelectContent({
                    content_type: 'cta',
                    content_id: 'aba_todos',
                    location_1: 'monetizacao',
                    location_2: 'hub_recompensas_spmais',
                    location_3: 'extrato_hub_recompensas',
                  });
                } else {
                  eventSelectContent({
                    content_type: 'cta',
                    content_id: 'aba_expirados',
                    location_1: 'monetizacao',
                    location_2: 'hub_recompensas_spmais',
                    location_3: 'extrato_hub_recompensas',
                  });
                }
                handleTabChange(index);
              }}
              type="options"
              isLoading={isLoadingExtract}
            />
        </Box>
      </BasicScreen>
      <PointsInfoBottomSheet modalizeRef={modalizeRefInfo} />
      {filterGroups.length > 0 && (
        <FiltersBottomSheet
          modalizeRef={modalizeRefFilters}
          filterGroups={filterGroups}
          onApplyFilters={handleApplyFilters}
          initialFilters={initialFilters}
        />
      )}
    </>
  );
};

export default PointsExtract;

