import { PointsExtractData, AppliedFilters } from '../../../redux/ducks/points';
import { NavigationProp } from '@react-navigation/native';
import { PropsRootStack } from '../../../routes/Models';

export type TransactionType = 'RECEIVED' | 'DEBIT' | 'EXPIRED' | 'REFUNDED';

export const DESCRIPTIONS = {
  RECEIVED: 'Ganhos',
  DEBIT: 'Usados',
  EXPIRED: 'Expirados',
  REFUNDED: 'Estornados',
} as const;

export interface PointsExtractProps {
  isLoadingExtract: boolean;
  isLoadingBalance: boolean;
  hasError: boolean;
  handleGoBack: () => void;
  pointsAvailable: number;
  extractData?: PointsExtractData;
  requestPointsExtract: () => void;
  appliedTransactionsFilters?: AppliedFilters;
  appliedExpiringFilters?: { period?: number };
  setTransactionsFilters: (filters: AppliedFilters) => void;
  clearTransactionsFilters: () => void;
  setExpiringFilters: (filters: { period?: number }) => void;
  clearExpiringFilters: () => void;
  navigation?: NavigationProp<PropsRootStack>;
}

