import { PropsIconsNameCore } from '@semparar/design-system-app';
import { PropsCardTransition } from '@semparar/design-system-app/src/atomic/molecules/CardTransition/Models';
import { propsItemsListCardTransition } from '@semparar/design-system-app/src/atomic/organisms/ListCardTransition/Models';
import { moment } from '../../../services/moment';
import { PointsTransaction, ProcessedExtractData } from '../../ducks/points';
import { NavigationProp } from '@react-navigation/native';
import { PropsRootStack } from '../../../routes/Models';
import { eventSelectContent } from '~/constants/functions';

type TransactionType = 'RECEIVED' | 'DEBIT' | 'EXPIRED' | 'REFUNDED';

const DESCRIPTIONS = {
  RECEIVED: 'Ganhos',
  DEBIT: 'Usados',
  EXPIRED: 'Expirados',
  REFUNDED: 'Estornados',
} as const;

const formatDateForHeader = (dateString: string): string => {
  return moment(dateString).format('DD [de] MMMM').toLowerCase();
};

const formatPointsValue = (amount: number, type: TransactionType): string => {
  const prefix = (type === 'RECEIVED' || type === 'REFUNDED') ? '+ ' : '- ';
  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} pontos`;
};

const getDescriptionSecondary = (type: TransactionType): string => {
  return DESCRIPTIONS[type] || '';
};

const capitalizeFirstLetter = (text: string): string => {
  return text.charAt(0).toUpperCase() + text.slice(1).toLowerCase();
};

const transformExpiredPointsTransaction = (
  transaction: PointsTransaction,
): propsItemsListCardTransition => {
  return {
    type: 'default' as const,
    bgColor: 'INTENSE_COLOR_01' as const,
    titleColor: 'BRAND_COMPLEMENT_01' as const,
    isSelected: false,
    showIcon: false,
    showRightIcon: false,
    showBackgroundLeftIcon: false,
    title: `${transaction.amount} pontos`,
    titleType: 'paragraphXL',
    value: 'Expiram em',
    descriptionSecondary: formatDateForHeader(transaction.date),
    descriptionSecondaryColor: 'INTENSE_COLOR_05',
    descriptionSecondaryType: 'paragraphMDM',
    valueColor: 'BRAND_COMPLEMENT_01',
    valueType: 'paragraphMD',
    description: undefined,
    labelBgColor: 'BRAND_COMPLEMENT_02' as any,
    showLabel: false,
  };
};

const transformPointsTransactionToItem = (
  transaction: PointsTransaction,
  navigation?: NavigationProp<PropsRootStack>,
): PropsCardTransition => {
  const valueColor =
    (transaction.type === 'RECEIVED' || transaction.type === 'REFUNDED') ? 'PLUS_COLOR_02' : 'BRAND_COMPLEMENT_01';

  return {
    type: 'default' as const,
    bgColor: 'INTENSE_COLOR_01' as const,
    titleColor: 'BRAND_COMPLEMENT_01' as const,
    isSelected: true,
    leftIcon:
      transaction.type === 'EXPIRED'
        ? 'icon-less'
        : (transaction.icon as PropsIconsNameCore),
    leftIconColor: 'BRAND_COMPLEMENT_01',
    labelBgColor: 'BRAND_COMPLEMENT_03',
    showBackgroundLeftIcon: true,
    title: capitalizeFirstLetter(transaction.description),
    description: undefined,
    value: formatPointsValue(transaction.amount, transaction.type),
    valueColor,
    descriptionSecondary: getDescriptionSecondary(transaction.type),
    descriptionSecondaryColor: 'INTENSE_COLOR_04',
    showIcon: true,
    rightIcon: 'icon-next',
    showRightIcon: transaction.type !== 'EXPIRED',
    onPress: navigation ? () => {
      eventSelectContent({
        content_type: 'cta',
        content_id: 'detalhe_ponto',
        location_1: 'monetizacao',
        location_2: 'hub_recompensas_spmais',
        location_3: 'extrato_hub_recompensas',
      });
      navigation.navigate('PointsDetail', { transaction });
    } : undefined,
  };
};

interface GroupedTransactions {
  date: string;
  items: Array<propsItemsListCardTransition>;
}

const groupPointsTransactionsByDate = (
  transactions: PointsTransaction[],
  filterToExpire = false,
  navigation?: NavigationProp<PropsRootStack>,
): GroupedTransactions[] => {
  if (!transactions?.length) {
    return [];
  }

  const filteredTransactions = filterToExpire
    ? transactions.filter(transaction => transaction.type === 'EXPIRED')
    : transactions;

  const sortedTransactions = [...filteredTransactions].sort((a, b) =>
    moment(b.date).diff(moment(a.date)),
  );

  const groupedByDate = sortedTransactions.reduce((acc, transaction) => {
    const formattedDate = formatDateForHeader(transaction.date);

    if (!acc[formattedDate]) {
      acc[formattedDate] = [];
    }

    if (filterToExpire) {
      acc[formattedDate].push(transformExpiredPointsTransaction(transaction));
    } else {
      acc[formattedDate].push(
        transformPointsTransactionToItem(
          transaction,
          navigation,
        ) as propsItemsListCardTransition,
      );
    }
    return acc;
  }, {} as Record<string, Array<propsItemsListCardTransition>>);

  const sortItemsByDate = (
    items: Array<propsItemsListCardTransition>,
    date: string,
  ) => {
    return items.sort((a, b) => {
      const transactionA = filteredTransactions.find(
        t =>
          formatDateForHeader(t.date) === date &&
          transformPointsTransactionToItem(t, navigation).title === a.title,
      );
      const transactionB = filteredTransactions.find(
        t =>
          formatDateForHeader(t.date) === date &&
          transformPointsTransactionToItem(t, navigation).title === b.title,
      );

      if (transactionA && transactionB) {
        return moment(transactionB.date).diff(moment(transactionA.date));
      }
      return 0;
    });
  };

  const sortByDate = (a: GroupedTransactions, b: GroupedTransactions) => {
    const dateA = moment(a.date.split(' ').slice(1).join(' '), 'DD MMMM');
    const dateB = moment(b.date.split(' ').slice(1).join(' '), 'DD MMMM');
    return dateB.diff(dateA);
  };

  return Object.entries(groupedByDate)
    .map(([date, items]) => ({
      date,
      items: sortItemsByDate(items, date),
    }))
    .sort(sortByDate);
};

class PointsDataGroupedByDayMapper {
  public static map(
    groupedData: Array<{
      date: string;
      items: Array<propsItemsListCardTransition>;
    }>,
    showLabels = true,
  ): propsItemsListCardTransition[] {
    if (!groupedData) return [];

    return groupedData.flatMap(({ date: label, items }) =>
      items?.map((item, index) => ({
        ...item,
        label,
        showLabel: showLabels ? index === 0 : false,
      })),
    ) as propsItemsListCardTransition[];
  }
}

interface ExpiringPoint {
  amount: number;
  expirationDate: string;
}

const transformExpiringPointsToTransactions = (
  expiringPoints: ExpiringPoint[],
): PointsTransaction[] => {
  return expiringPoints.map(point => ({
    id: `expiring-${point.amount}-${point.expirationDate}`,
    date: point.expirationDate,
    type: 'EXPIRED' as const,
    description: `${point.amount} pontos`,
    amount: point.amount,
    currencyValue: 0,
    icon: 'icon-clock',
    details: {
      provider: 'system',
      extraInfo: 'Pontos a expirar',
      fields: [],
    },
  }));
};

interface ExtractData {
  transactions?: PointsTransaction[];
  expiringPoints?: ExpiringPoint[];
}

const DEFAULT_EXTRACT_DATA: ProcessedExtractData = {
  groupedTransactions: [],
  groupedExpiring: [],
  mappedTransactions: [],
  mappedExpiring: [],
};

export const processPointsExtractData = (
  extractData: ExtractData | null | undefined,
  navigation?: NavigationProp<PropsRootStack>,
): ProcessedExtractData => {
  if (!extractData || typeof extractData !== 'object') {
    return DEFAULT_EXTRACT_DATA;
  }

  try {
    const transactions = extractData.transactions || [];
    const expiringPoints = extractData.expiringPoints || [];

    const groupedTransactions = groupPointsTransactionsByDate(
      transactions,
      false,
      navigation,
    );
    const mappedTransactions =
      PointsDataGroupedByDayMapper.map(groupedTransactions);

    const expiringTransactions =
      transformExpiringPointsToTransactions(expiringPoints);
    const mappedExpiringPoints = expiringTransactions.map(
      transformExpiredPointsTransaction,
    );

    return {
      groupedTransactions,
      groupedExpiring: [],
      mappedTransactions,
      mappedExpiring: mappedExpiringPoints,
    };
  } catch (error) {
    console.warn('Erro ao processar dados do extrato:', error);
    return DEFAULT_EXTRACT_DATA;
  }
};

