    34→  processedExtractData: undefined,
    35→  status: PointsExtractStatus.IDLE,
    36→  isLoadingMore: false,
    37→  error: undefined,
    38→};
    39→
    40→const INITIAL_POINTS_BALANCE_STATE: PointsBalanceState = {
    41→  points: undefined,
    42→  status: PointsBalanceStatus.IDLE,
    43→  error: undefined,
    44→};
    45→
    46→const INITIAL_POINTS_EXTRACT_FILTERS_STATE: PointsExtractFiltersState = {
    47→  appliedTransactionsFilters: undefined,
    48→};
    49→
    50→export const createPointsExtractSlice: StateCreator<
    51→  PointsExtractSlice,
    52→  [],
    53→  [],
    54→  PointsExtractSlice
