    56→  pointsExtract: INITIAL_POINTS_EXTRACT_STATE,
    57→  pointsBalance: INITIAL_POINTS_BALANCE_STATE,
    58→  pointsExtractFilters: INITIAL_POINTS_EXTRACT_FILTERS_STATE,
    59→  pointsExtractActions: {
    60→    setExtractStatus: (status) =>
    61→      set((state) => ({
    62→        pointsExtract: { ...state.pointsExtract, status },
    63→      })),
    64→    setExtractData: (extractData, processedExtractData) =>
    65→      set((state) => ({
    66→        pointsExtract: {
    67→          ...state.pointsExtract,
    68→          extractData,
    69→          processedExtractData,
    70→          status: PointsExtractStatus.SUCCESS,
    71→          isLoadingMore: false,
    72→          error: undefined,
    73→        },
    74→      })),
    75→    appendExtractData: (extractData, processedExtractData) =>
    76→      set((state) => {
    77→        const existingTransactions = state.pointsExtract.extractData?.transactions ?? [];
    78→        const newTransactions = extractData.transactions;
    79→        const mergedTransactions = [...existingTransactions, ...newTransactions];
    80→
