import type { StateCreator } from 'zustand';
import type { AirlineMilesActions, AirlineMilesState } from '../models';

export type AirlineMilesSlice = {
  airlineMiles: AirlineMilesState;
  airlineMilesActions: AirlineMilesActions;
};

const initialAirlineMilesState: AirlineMilesState = {
  redirectURL: '',
  isLoading: false,
  isError: false,
  errorMessage: '',
};

export const createAirlineMilesSlice: StateCreator<
  AirlineMilesSlice,
  [],
  [],
  AirlineMilesSlice
> = (set) => ({
  airlineMiles: initialAirlineMilesState,

  airlineMilesActions: {
    setRedirectURL: (url) =>
      set((state) => ({
        airlineMiles: {
          ...state.airlineMiles,
          redirectURL: url,
          isLoading: false,
          isError: false,
          errorMessage: '',
        },
      })),

    setLoading: (isLoading) =>
      set((state) => ({
        airlineMiles: {
          ...state.airlineMiles,
          isLoading,
          ...(isLoading && {
            isError: false,
            errorMessage: '',
          }),
        },
      })),

    setError: (error) =>
      set((state) => ({
        airlineMiles: {
          ...state.airlineMiles,
          isLoading: false,
          isError: true,
          errorMessage: error,
        },
      })),

    clearError: () =>
      set((state) => ({
        airlineMiles: {
          ...state.airlineMiles,
          isError: false,
          errorMessage: '',
        },
      })),

    reset: () =>
      set({
        airlineMiles: initialAirlineMilesState,
      }),
  },
});

