export interface AirlineMilesMarketplaceParams {}

export interface AirlineMilesMarketplaceState {
  isWebViewError: boolean;
  redirectURL: string;
  isLoading: boolean;
  isError: boolean;
  webViewRef: RefObject<WebViewProps | null>;
}

export interface AirlineMilesMarketplaceHandlers {
  handleGoBack: () => void;
  handleWebViewError: (event?: WebViewErrorEvent) => void;
  handleRetry: () => void;
}

export type UseAirlineMilesMarketplaceReturn = AirlineMilesMarketplaceState &
  AirlineMilesMarketplaceHandlers;

export interface AirlineMilesMarketplaceScreenProps
  extends NativeStackScreenProps<PropsRootStack, 'AirlineMilesMarketplace'> {}

import { useCallback, useEffect, useRef, useState } from 'react';
import { useFocusEffect } from '@react-navigation/native';
import type { WebViewProps } from '../../atomic/templates/WebViewScreen/Models';
import { useScreenViewTracking } from '../../hooks/tracking';
import { useAirlineMiles } from '../../services/hooks/useAirlineMiles';
import type {
  AirlineMilesMarketplaceScreenProps,
  UseAirlineMilesMarketplaceReturn,
} from './Models';

export function useAirlineMilesMarketplace(
  props: AirlineMilesMarketplaceScreenProps
): UseAirlineMilesMarketplaceReturn {
  const { navigation, route } = props;
  useScreenViewTracking({ route, title: 'Milhas Aéreas' });

  const [isWebViewError, setIsWebViewError] = useState(false);
  const webViewRef = useRef<WebViewProps>(null);

  const {
    redirectURL,
    isLoading,
    isError,
    fetchAirlineMilesToken,
    reset,
  } = useAirlineMiles();

  useFocusEffect(
    useCallback(() => {
      let isActive = true;

      const fetchData = async () => {
        if (isActive) {
          setIsWebViewError(false);
        }
        await fetchAirlineMilesToken();
      };

      fetchData();

      return () => {
        isActive = false;
      };
    }, [fetchAirlineMilesToken])
  );

  useEffect(() => {
    return () => {
      reset();
    };
  }, [reset]);

  const handleGoBack = useCallback(() => {
    navigation.goBack();
  }, [navigation]);

  const handleWebViewError = useCallback(() => {
    setIsWebViewError(true);
  }, []);

  const handleRetry = useCallback(() => {
    setIsWebViewError(false);
    fetchAirlineMilesToken();
  }, [fetchAirlineMilesToken]);

  return {
    isWebViewError,
    redirectURL,
    isLoading,
    isError,
    webViewRef,
    handleGoBack,
    handleWebViewError,
    handleRetry,
  };
}

export { default } from './view';

import React from 'react';
import AnimationArrows from '../../atomic/atoms/AnimationArrows';
import BasicScreen from '../../atomic/templates/BasicScreen';
import ApiError from '../../atomic/organisms/ApiError';
import { WebViewScreen } from '../../atomic/templates/WebViewScreen';
import { useAirlineMilesMarketplace } from './index';
import type { AirlineMilesMarketplaceScreenProps } from './Models';

const SCREEN_TITLE = 'Milhas Aéreas';

export default function AirlineMilesMarketplaceScreen(props: AirlineMilesMarketplaceScreenProps) {
  const {
    isWebViewError,
    redirectURL,
    isLoading,
    isError,
    webViewRef,
    handleGoBack,
    handleWebViewError,
    handleRetry,
  } = useAirlineMilesMarketplace(props);

  if (isLoading) {
    return <AnimationArrows />;
  }

  if (isError || !redirectURL || isWebViewError) {
    return (
      <BasicScreen
        leftIconOnPress={handleGoBack}
        title={SCREEN_TITLE}
        errorButtonOnPress={handleRetry}
      >
        <ApiError onPress={handleRetry} />
      </BasicScreen>
    );
  }

  return (
    <WebViewScreen
      uri={redirectURL}
      title={SCREEN_TITLE}
      webViewRef={webViewRef}
      onBackPress={handleGoBack}
      onError={handleWebViewError}
      onRetry={handleRetry}
    />
  );
}

